531			}
532			t.log.Info("reload: path added", "path", def.Name)
533		}
534		for _, name := range remove {
535			if err := t.bind.RemovePath(name); err != nil {
536				return fmt.Errorf("device: reload remove path %q: %w", name, err)
537			}
