539		}
540		// Advance the running config to the membership now in service. Survivors keep their
541		// ORIGINAL parameters and all non-path fields stay as booted (the ignored changes
542		// were not applied), so a subsequent identical reload re-warns about a still-diverged
543		// file rather than silently accepting it. Metrics.Listen is carried to the applied
544		// value so a subsequent reload diffs against the endpoint actually running.
545		t.cfg = runningConfig(t.cfg, add, remove)
