609	// on both sides (it is the name intersection), so a positional mismatch is a reorder.
610	func reordered(live, desired []config.Path) bool {
611		desiredNames := make(map[string]struct{}, len(desired))
612		for _, p := range desired {
613			desiredNames[p.Name] = struct{}{}
614		}
615		liveNames := make(map[string]struct{}, len(live))
616		for _, p := range live {
617			liveNames[p.Name] = struct{}{}
618		}
619		var liveCommon, desiredCommon []string
620		for _, p := range live {
621			if _, ok := desiredNames[p.Name]; ok {
622				liveCommon = append(liveCommon, p.Name)
623			}
624		}
625		for _, p := range desired {
626			if _, ok := liveNames[p.Name]; ok {
627				desiredCommon = append(desiredCommon, p.Name)
628			}
629		}
630		for i := range liveCommon {
631			if liveCommon[i] != desiredCommon[i] {
632				return true
633			}
634		}
635		return false
636	}
637	
638	// runningConfig advances the running config to the membership the bind now serves:
639	// the survivors (live paths not removed, keeping their ORIGINAL parameters and order)
640	// followed by the added paths (their new parameters). Non-path fields are carried over
641	// unchanged — a membership-only reload does not re-apply them. It mirrors the m.defs
642	// order the bind rebuilds on a Close→Open (survivors-in-order, then appended adds).
643	func runningConfig(live *config.Config, add []config.Path, remove []string) *config.Config {
644		removeSet := make(map[string]struct{}, len(remove))
645		for _, n := range remove {
646			removeSet[n] = struct{}{}
647		}
648		paths := make([]config.Path, 0, len(live.Paths)+len(add))
649		for _, p := range live.Paths {
650			if _, gone := removeSet[p.Name]; !gone {
651				paths = append(paths, p)
652			}
653		}
654		paths = append(paths, add...)
655		running := *live
656		running.Paths = paths
657		return &running
658	}
659	
660	// diffPaths computes, by name, which desired paths are not yet live (to add) and
661	// which live paths are no longer desired (to remove). It is a pure function so the
662	// reload diff is unit-testable without a running engine.
663	func diffPaths(live []string, desired []config.Path) (add []config.Path, remove []string) {
664		liveSet := make(map[string]struct{}, len(live))
665		for _, n := range live {
666			liveSet[n] = struct{}{}
667		}
668		desiredSet := make(map[string]struct{}, len(desired))
669		for _, p := range desired {
670			desiredSet[p.Name] = struct{}{}
671			if _, ok := liveSet[p.Name]; !ok {
672				add = append(add, p)
673			}
674		}
675		for _, n := range live {
676			if _, ok := desiredSet[n]; !ok {
677				remove = append(remove, n)
678			}
679		}
680		return add, remove
681	}
682	
